import path from "path";
import { execa } from "execa";
import getRegistry from "./get-registry.js";
import getChannel from "./get-channel.js";
import getReleaseInfo from "./get-release-info.js";
import fs from "fs"

export default async function (npmrc, { npmPublish, pkgRoot }, pkg, context) {
  const {
    cwd,
    env,
    stdout,
    stderr,
    nextRelease: { version, channel },
    logger,
  } = context;

  if (npmPublish !== false && pkg.private !== true) {
    const basePath = pkgRoot ? path.resolve(cwd, pkgRoot) : cwd;
    const registry = getRegistry(pkg, context);
    const distTag = getChannel(channel);

    logger.log(`env contents:\n${JSON.stringify(env, null, 2)}`);

    // Workaround for trusted publishing: https://github.com/semantic-release/npm/issues/1054
    const publishEnv = { ...env };
    delete publishEnv.NPM_TOKEN;
    delete publishEnv.NODE_AUTH_TOKEN;

    logger.log(`npmrc contents:\n${fs.readFileSync(npmrc, "utf8")}`);
    logger.log(`NPM_TOKEN set: ${"NPM_TOKEN" in publishEnv}, NODE_AUTH_TOKEN set: ${"NODE_AUTH_TOKEN" in publishEnv}`);

    const { stdout: npmVersion } = await execa("npm", ["--version"], { env, preferLocal: true });
    const { stdout: nodeVersion } = await execa("node", ["--version"], { env, preferLocal: true });

    logger.log(`npm version: ${npmVersion.trim()}`);
    logger.log(`node version: ${nodeVersion.trim()}`);

    logger.log(`Publishing version ${version} to npm registry on dist-tag ${distTag}`);
    const result = execa(
      "npm",
      ["publish", basePath, "--userconfig", npmrc, "--tag", distTag, "--registry", registry],
      { cwd, env: publishEnv, preferLocal: true }
    );
    result.stdout.pipe(stdout, { end: false });
    result.stderr.pipe(stderr, { end: false });
    await result;

    logger.log(`Published ${pkg.name}@${version} to dist-tag @${distTag} on ${registry}`);

    return getReleaseInfo(pkg, context, distTag, registry);
  }

  logger.log(
    `Skip publishing to npm registry as ${npmPublish === false ? "npmPublish" : "package.json's private property"} is ${
      npmPublish !== false
    }`
  );

  return false;
}
